    private static final LocalDate START_WERKBONUS_HERSTRUCTURERING = new LocalDate(2004, 7, 1);
    private static final LocalDate START_2018 = new LocalDate(2018, 1, 1);
    private static final LocalDate APRIL_2018 = new LocalDate(2018, 4, 1);
    private static final LocalDate START_CONSTANT_LEEFTIJD = new LocalDate(2007, 1, 1);

    private static final Set<Sleutel<?>> WERKBONUS_SLEUTEL = ImmutableSet
            .of(SleutelCategorie.INSTANCE, SleutelPensioenStelsel.INSTANCE, SleutelWerkgeversCategorie.INSTANCE, SleutelWerknemersKengetal.INSTANCE,
                    SleutelMaatman.INSTANCE, SleutelAanstelling.INSTANCE, SleutelNaceCode.INSTANCE, SleutelDienstverband.INSTANCE,
                    SleutelVerminderingsCodeWerkbonus.INSTANCE, SleutelTypeArbeidsOvereenkomst.INSTANCE, SleutelStatuutDmfappl.INSTANCE,
                    SleutelVrijstellingTweedePensioenpijler.INSTANCE, SleutelWijzeBezoldiging.INSTANCE, SleutelMaatregelingReorganisatieArbeidsTijd.INSTANCE,
                    SleutelMaatregelingReorganisatieArbeidsTijd2.INSTANCE, SleutelVestigingsId.INSTANCE, SleutelDatumVasteBenoeming.INSTANCE,
                    SleutelSocialeMaribel.INSTANCE, SleutelMaatregelinBevorderingWerk.INSTANCE, SleutelNotieGepensioneerd.INSTANCE,
