    private final ConstantManager constantManager;
    private final BijdragePercentagesFactory bijdragePercentagesFactory;
    private final RegimeRszppoService regimeRszppoService;
    private final DmfapplBasisBijdrageService dmfapplBasisBijdrageService;

    public BerekenVerminderingHerstructureringDmfappl(ConstantManager constantManager, NlpGlobalService globalService) {
        this.constantManager = constantManager;
        this.bijdragePercentagesFactory = new BijdragePercentagesFactoryImp(constantManager, globalService);
        this.dmfapplBasisBijdrageService = globalService.getDmfapplBasisBijdrageService();
        this.regimeRszppoService = globalService.getRegimeRszppoService();
    }

    @Override
    protected boolean execute(RekenContext context) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        if (rekenTijd.beginDatum.isAfter(START_WERKBONUS_HERSTRUCTURERING.minusDays(1))) {
            Money totaalBedragVermindering = Money.ZERO;
            Persoon persoon = context.getUnchecked(RekenChainKey.PERSOON_KEY);
            LoonElementManager manager = context.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
            RegulManager regulManager = context.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
            Set<Opdracht> opdrachten = persoon.getOpdrachten();
            for (Opdracht opdracht : opdrachten) {
                if (komtInAanMerkingOpdracht(context, manager, opdracht, rekenTijd, regulManager)) {
                    RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
                    totaalBedragVermindering = totaalBedragVermindering.add(berekenVermindering(opdrachtContext, opdracht));
                }
            }
            Money begrenstOpForfait = begrensOpForfait(totaalBedragVermindering, rekenTijd);
            if (totaalBedragVermindering.signum() > 0) {
                for (Opdracht opdracht : opdrachten) {
                    RekenContext opdrachtContext = context.getOpdrachtContext(opdracht);
                    Money bedragVermindering = opdrachtContext.getMoney(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY);
                    bedragVermindering = bedragVermindering.multiply(begrenstOpForfait.divide(totaalBedragVermindering));
                    opdrachtContext.put(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY, bedragVermindering);
                    verdeelVermindering(context, bedragVermindering, opdrachtContext, opdracht, rekenTijd);
                }
            }

        }
        return CONTINUE_PROCESSING;
    }

    private void verdeelVermindering(
            RekenContext mainContext, Money bedragVermindering, RekenContext opdrachtContext, Opdracht opdracht,
            RekenTijd rekenTijd) {
        LoonElementManager manager = opdrachtContext.getUnchecked(RekenChainKey.LOONELEMENT_MANAGER_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        SortedSet<LoonElement> werkBonusElementen = LoonElement.createSortedSet();
        for (LoonElement loonElement : manager.getOpdrachtsElementen(opdracht)) {
            SleutelGegevensSingleOpper gegevens = new SleutelGegevensSingleOpper(loonElement.getOpper());
            if (komtInAanMerkingOpdracht(mainContext, manager, opdracht, rekenTijd, regulManager)
                    && komtInAanMerkingSleutelGegevens(gegevens, rekenTijd, regulManager)) {
                werkBonusElementen.add(loonElement);
            }
        }

        Money totaalBasis = Money.ZERO;
        Money negatieveBijdragen = Money.ZERO;
        for (LoonElement loonElement : werkBonusElementen) {
            Money basis = loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY);
            basis = basis.add(loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_TAO_KEY));
            if (basis.signum() > 0) {
                totaalBasis = totaalBasis.add(basis);
            }
            Money bijdrage = loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
            bijdrage = bijdrage.add(loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY));
            if (bijdrage.signum() < 0) {
                negatieveBijdragen = negatieveBijdragen.add(bijdrage);
            }
        }
        Money carry = Money.ZERO;
        Money carryNegatief = Money.ZERO;
        Money totaalVermindering = Money.ZERO;
        log.debug("verdeelVermindering-bedragVermindering:{};totaalBasis:{}", bedragVermindering, totaalBasis);
        for (LoonElement loonElement : werkBonusElementen) {
            Money basis = loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_RSZ_KEY);
            basis = basis.add(loonElement.getPropertyMoney(RekenBasisRszKey.BASIS_TAO_KEY));
            log.debug("basis:{};loonElement:{}", basis, loonElement);
            if (basis.signum() > 0) {
                Money elementVermindering = bedragVermindering.multiply(basis.divide(totaalBasis)).add(carry);
                Money deelNegatief = negatieveBijdragen.multiply(basis.divide(totaalBasis)).add(carryNegatief);
                carryNegatief = deelNegatief.subtract(deelNegatief.round(2));
                deelNegatief = deelNegatief.round(2);
                Money bijdrage = loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
                bijdrage = bijdrage.add(deelNegatief);
                bijdrage = bijdrage.add(loonElement.getPropertyMoney(RekenRszKey.BIJDRAGE_TAO_KEY));
                elementVermindering = elementVermindering.min(bijdrage);
                carry = elementVermindering.subtract(elementVermindering.round(2));
                elementVermindering = elementVermindering.round(2);
                log.debug("elementVermindering:{};carry:{}", elementVermindering, carry);
                totaalVermindering = totaalVermindering.add(elementVermindering);
                loonElement.putProperty(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY, elementVermindering);
            }
        }
        opdrachtContext.put(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY, totaalVermindering);
    }

    private Money begrensOpForfait(Money bedragVermindering, RekenTijd rekenTijd) {
        Money forfaitairBedrag = constantManager.getActualConstant(Konstanten.KST_HERSTRUCT_FF, rekenTijd).getMoney();
        return bedragVermindering.min(forfaitairBedrag);

    }

    private Money berekenVermindering(RekenContext opdrachtContext, Opdracht opdracht) {
        RekenTijd rekenTijd = opdrachtContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        RegulManager regulManager = opdrachtContext.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
        SleutelSamenNemer aggregator = new SleutelSamenNemer();
        List<SleutelGegevens> aggregaten = aggregator.neemSamenVoorSleutel(opdracht, WERKBONUS_SLEUTEL);
        Money totaalBedragVermindering = Money.ZERO;
        for (SleutelGegevens aggregaat : aggregaten) {

            if (komtInAanMerkingSleutelGegevens(aggregaat, rekenTijd, regulManager)) {
                Money forfait = constantManager.getActualConstant(Konstanten.KST_HERSTRUCT_FF, rekenTijd).getMoney();
                if (forfait.signum() > 0) {
                    Money bedragVermindering = berekeningVermindering(opdrachtContext, aggregaat, forfait, rekenTijd);
                    bedragVermindering = begrensWerkbonusHerstructurering(opdrachtContext, bedragVermindering);
                    totaalBedragVermindering = totaalBedragVermindering.add(bedragVermindering);
                }
            }
        }
        opdrachtContext.put(RekenRszKey.VERMINDERING_HERSTRUCTERING_KEY, totaalBedragVermindering);
        return totaalBedragVermindering;
    }

    protected static final LocalDate GRENS_NIEUWE_VERDELING = new LocalDate(2007, 7, 1);

    private Money begrensWerkbonusHerstructurering(RekenContext context, Money werkbonusHerstructurering) {
        RekenTijd rekenTijd = context.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        boolean nieuweVerdeling = !rekenTijd.beginDatum.isBefore(GRENS_NIEUWE_VERDELING);
        Opper opperLaatsteGegevens = context.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);

        Money bijdrageRsz = context.getMoney(RekenRszKey.BIJDRAGE_RSZ_KEY);
        if (nieuweVerdeling) {
            RegulManager regulManager = context.getUnchecked(RekenChainKey.REGUL_MANAGER_KEY);
            BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
            BigDecimal percentageBijdrageRsz = bijdragePercentages.getInhoudingRsz(new SleutelGegevensSingleOpper(opperLaatsteGegevens));
            Money basisRszNietLageLonen = context.getMoney(RekenBasisRszKey.BASIS_NIET_LAGE_LONEN_KEY);
            Money bijdrageRszNietLageLonen = basisRszNietLageLonen.multiply(percentageBijdrageRsz).round(2);
            werkbonusHerstructurering = werkbonusHerstructurering.min(bijdrageRsz.subtract(bijdrageRszNietLageLonen)).max(Money.ZERO);
        } else {
            werkbonusHerstructurering = werkbonusHerstructurering.min(bijdrageRsz);
        }
        return werkbonusHerstructurering;
    }

    private Money berekeningVermindering(RekenContext opdrachtContext, SleutelGegevens gegevens, Money basisBedrag, RekenTijd rekenTijd) {
        PrestatieSamenvatting prestatieSamenvatting = gegevens.getPrestatieSamenvatting(opdrachtContext);
        BigDecimal hWaarde = prestatieSamenvatting.getHwaarde();
        BigDecimal weekdagen = AantalRszDagen.inMaand(5, rekenTijd.rekenPeriode);
        BigDecimal maatman = gegevens.getMaatman();
        BigDecimal uren = maatman.multiply(weekdagen).divide(BigDecimal.valueOf(5), 3, RoundingMode.HALF_UP);

        BigDecimal verhouding = hWaarde.divide(uren, 2, RoundingMode.HALF_UP).min(BigDecimal.ONE);
        return basisBedrag.multiply(verhouding).round(2);
    }

    private static final Set<RszppoKategorie> RSZPPO_CATEGORIE_HERSTRUCT =
            Sets.immutableEnumSet(RszppoKategorie.HA_HSTR_PR, RszppoKategorie.HA_HSTR_PU, RszppoKategorie.HO_HSTR_PR, RszppoKategorie.HO_HSTR_PU);

    public boolean komtInAanMerkingSleutelGegevens(SleutelGegevens aggregaat, RekenTijd rekenTijd, RegulManager regulManager) {
        boolean inAanmerkingVoorWerkbonus;
        if (RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.DMFAPPL) {
            WerkgeversCategorie werkgeversCategorie = aggregaat.getWerkgeversCategorie();
            DmfapplWnkengetal werknemersKengetal = aggregaat.getWerknemersKengetal();
            CategorieKengetal categorieKengetal = CategorieKengetalFactory.getCategorieKengetal(rekenTijd, werkgeversCategorie, werknemersKengetal);

            inAanmerkingVoorWerkbonus = !categorieKengetal.isStudentMetBijzondereCategorie();
            DmfapplCodeVermin verminderingscode = aggregaat.getVerminderingsCodeWerkbonus();
            inAanmerkingVoorWerkbonus = inAanmerkingVoorWerkbonus && (verminderingscode == DmfapplCodeVermin.DMFAPPL_CODE_VERMIN_0601
                    || verminderingscode == DmfapplCodeVermin.DMFAPPL_CODE_VERMIN_0600);
        } else {
            inAanmerkingVoorWerkbonus = RSZPPO_CATEGORIE_HERSTRUCT.contains(aggregaat.getCategorie());
        }
        if (inAanmerkingVoorWerkbonus) {
            inAanmerkingVoorWerkbonus = !aggregaat.isOnregelmatigPerPrestatieOfPerUur();
        }
        if (inAanmerkingVoorWerkbonus) {
            BijdragePercentages bijdragePercentages = bijdragePercentagesFactory.create(rekenTijd, regulManager);
            BigDecimal percentageBijdrageRsz = bijdragePercentages.getInhoudingRsz(aggregaat);
            inAanmerkingVoorWerkbonus = percentageBijdrageRsz.compareTo(new BigDecimal("0.1307")) == 0;
        }
        return inAanmerkingVoorWerkbonus;
    }

    public boolean komtInAanMerkingOpdracht(RekenContext mainContext, LoonElementManager manager, Opdracht opdracht, RekenTijd rekenTijd, RegulManager regulManager) {
        boolean komtInAanMerking = komtInAanMerkingHoedanigheid(opdracht, rekenTijd);
        boolean aanwezig601 = aanwezig601(opdracht);

        if (aanwezig601) {
            komtInAanMerking = komtInAanMerking && onderzoekMaandelijkseLoonMassa(mainContext, manager, opdracht, rekenTijd, regulManager);
        }
        return komtInAanMerking;
    }

    private boolean aanwezig601(Opdracht opdracht) {
        boolean aanwezig601 = false;
        for (Opper opper : opdracht.getOpperSlices()) {
            if (opper.getRszppo().getCodeWerkbonus() == DmfapplCodeVermin.DMFAPPL_CODE_VERMIN_0601) {
                aanwezig601 = true;
            }
        }
        return aanwezig601;
    }

    private static final Set<Hoedanigheid> KOMT_IN_AAN_MERKING =
            Sets.immutableEnumSet(Hoedanigheid.WACHTWEDDEN, Hoedanigheid.VASTBENOEMDEN, Hoedanigheid.TIJDELIJKEN_EN_CONTRACTUELEN,
                    Hoedanigheid.GESUBSIDIEERDE_CONTRACTUELEN, Hoedanigheid.STUDENTEN, Hoedanigheid.MONITOREN, Hoedanigheid.TOEZICHT_BEGELEIDING_BIJLES,
                    Hoedanigheid.ANDERE, Hoedanigheid.ERKENTELIJKHEIDSPREMIE, Hoedanigheid.VRIJWILLIGE_BRANDWEER_ERKENTELIJKHEIDSPREMIE,
                    Hoedanigheid.MANDATARISSEN_NIET_BESCHERMD, Hoedanigheid.VRIJWILLIGE_BRANDWEER, Hoedanigheid.ONTHAALOUDERS);

    //rszppoPlichtig
    public boolean komtInAanMerkingHoedanigheid(Opdracht opdracht, RekenTijd rekenTijd) {
        Hoedanigheid hoedanigheid = opdracht.getHoedanigheid();
        return KOMT_IN_AAN_MERKING.contains(hoedanigheid) || (hoedanigheid == Hoedanigheid.VRIJWILLIGERS
                && RekenTools.getTijdperk(rekenTijd) == AkeTijdperk.RSZPPO);
    }

    private boolean onderzoekMaandelijkseLoonMassa(
            RekenContext mainContext, LoonElementManager manager, Opdracht opdracht, RekenTijd rekenTijd,
            RegulManager regulManager) {
        LocalDate begindatumRecht = getBeginDatumVerminderingHerstructurering(opdracht, rekenTijd, regulManager);
        LocalDate geboortedatum = opdracht.getPersoon().getGeboorteDatum();
        int leeftijd = Years.yearsBetween(geboortedatum, begindatumRecht).getYears();

        LocalDate selectieDatumLeeftijd = Ordering.natural().max(rekenTijd.beginDatum, START_CONSTANT_LEEFTIJD);
        int leeftijdGrens = constantManager.getByCodeDatum(Konstanten.KST_HERSTRUCT_LEEFTIJD_30, selectieDatumLeeftijd).getInteger();
        Konstanten bovengrensConstant;
        if (leeftijd < leeftijdGrens) {
            bovengrensConstant = Konstanten.KST_HERSTRUCT_BOVENGRENS_JONGER_DAN_30;

        } else if (opdracht.getBeginDatum().isBefore(START_2018)) {
            bovengrensConstant = Konstanten.KST_HERSTRUCT_BOVENGRENS_OUDER_DAN_30;
        } else {
            bovengrensConstant = Konstanten.KST_HERSTRUCT_BOVENGRENS_OUDER_DAN_30_VANAF_2018;
        }

        Money bovengrens = constantManager.getByCodeDatum(bovengrensConstant, selectieDatumLeeftijd).getMoney();
        Money maandelijkseLoonmassa = bepaalMaandelijkseLoonMassa(mainContext, opdracht.getPersoon(), manager, rekenTijd);
        return maandelijkseLoonmassa.compareTo(bovengrens) <= 0;
    }

    private LocalDate getBeginDatumVerminderingHerstructurering(Opdracht opdracht, RekenTijd rekenTijd, RegulManager regulManager) {
        LocalDate beginDatum = rekenTijd.beginDatum;
        LocalDate beginDatumRecht = null;

        for (Opper opper : opdracht.getOpperSlices()) {
            Rszppo rszppo = opper.getRszppo();

            // NLP-1239: dienstverband NEE, periodes uitsluiten van onderzoek
            if (rszppo.getDienstverband() == Dienstverband.JA) {
                if (beginDatumRecht == null) {
                    beginDatumRecht = rszppo.getBeginDatumVermindering();
                } else if (!beginDatumRecht.equals(rszppo.getBeginDatumVermindering())) {
                    regulManager.doRegulException(opdracht, Regulkode.HERSTRUCT_BD_VERMIN);
                }
            }
        }
        if (beginDatumRecht == null) {
            regulManager.doRegulException(opdracht, Regulkode.HERSTRUCT_BD_VERMIN);
            beginDatumRecht = beginDatum;
        }

        int beginDatumRechtKwartaal = beginDatumRecht.getYear() * 4 + TimeTools.bepaalKwartaal(beginDatumRecht);
        int huidigKwartaal = beginDatum.getYear() * 4 + TimeTools.bepaalKwartaal(beginDatum);
        //Gebruik van werkbonus herstructurering meer dan 3 kwartalen na indiensttreding
        if (huidigKwartaal - beginDatumRechtKwartaal + 1 > 3) {
            regulManager.doRegulException(opdracht, Regulkode.WERKB_HERSTRUCT_MEER_DAN_3_KW);
        } else if (beginDatumRechtKwartaal > huidigKwartaal) {
            regulManager.doRegulException(opdracht, Regulkode.HERSTRUCT_BD_VERMIN);
        }
        return beginDatumRecht;
    }

    private Money bepaalMaandelijkseLoonMassa(RekenContext mainContext, Persoon persoon, LoonElementManager manager, RekenTijd rekenTijd) {
        BigDecimal weekdagen = AantalRszDagen.inMaand(5, rekenTijd.rekenPeriode);
        Money maandelijkseLoonmassaTotaal = Money.ZERO;
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            Money maandelijkseLoonmassa = Money.ZERO;
            Collection<LoonElement> loonElementen = manager.getOpdrachtsElementen(opdracht);

            for (LoonElement element : loonElementen) {
                if (komtInAanMerkingLoonElement(element, rekenTijd)) {
                    maandelijkseLoonmassa = maandelijkseLoonmassa.add(element.getPropertyMoney(RekenBrutoKey.BASIS_SOCIALE_INHOUDINGEN_KEY));
                }
            }
            if (!rekenTijd.beginDatum.isBefore(APRIL_2018)) {
                RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
                BigDecimal hWaarde = BigDecimal.ZERO;
                for (Opper opper : opdracht.getOpperSlices()) {
                    PrestatieSamenvatting samenvatting = opdrachtContext.getDoubleKey(RekenChainKey.PRESTATIE_SAMENVATTING_KEY, opper);
                    hWaarde = hWaarde.add(samenvatting.getHwaarde());
                }
                Opper opper = opdrachtContext.getUnchecked(RekenChainKey.OPPER_LAATSTE_GEGEVENS_KEY);
                BigDecimal maatman = opper.getRszppo().getMaatman();
                BigDecimal uren = maatman.multiply(weekdagen).divide(BigDecimal.valueOf(5), 3, RoundingMode.HALF_UP);
                if (hWaarde.signum() != 0) {
                    maandelijkseLoonmassa = maandelijkseLoonmassa.divide(hWaarde).round(2).multiply(uren);
                }
            }
            maandelijkseLoonmassaTotaal = maandelijkseLoonmassaTotaal.add(maandelijkseLoonmassa);
        }
        return maandelijkseLoonmassaTotaal;
    }

    public boolean komtInAanMerkingLoonElement(LoonElement element, RekenTijd rekenTijd) {
        Opper opper = element.getOpper();
        Rszppo rszppo = opper.getRszppo();
        AardKodeExtensie loonCode = element.getAardKodeExtensie();
        boolean inAanmerkingVoorWerkbonus = !loonCode.behoortTotGroep(LooncodeGroepKeyStrings.GEEN_WERKBONUS_LAGE_LONEN_KEY);
        if (inAanmerkingVoorWerkbonus) {
            LocalDate datum = TimeTools.getZoekDatum(opper, rekenTijd.rekenPeriode);
            AkeTijdperk tijdperk = RekenTools.getTijdperk(rekenTijd);
            if (tijdperk == AkeTijdperk.RSZPPO) {
                inAanmerkingVoorWerkbonus =
                        BerekenWerkbonusRszppoHelperFactory.isInAanmerkingVoorWerkbonusRszppo(regimeRszppoService, rszppo.getCategorie(), loonCode, datum);
            } else {
                inAanmerkingVoorWerkbonus =
                        BerekenWerkbonusDmfapplHelperFactory.isInAanmerkingVoorWerkbonusDmfappl(dmfapplBasisBijdrageService, rekenTijd, rszppo.getWerkgeversCategorie(),
                                rszppo.getWerknemersKengetal(), loonCode, datum);
            }
        }
        return inAanmerkingVoorWerkbonus;
    }
